import { describe, it, expect, vi, beforeEach } from 'vitest';
import { decodeBundle, validateBundle } from '../../src/bundle.js';
import { BundleValidationError } from '../../src/errors.js';

// Mock verifyEd25519 — crypto behaviour is tested in crypto.test.js.
// Here we test validateBundle's logic (quorum counting, expiry, version).
vi.mock('../../src/crypto.js', async (importOriginal) => {
  const real = await importOriginal();
  return {
    ...real,
    verifyEd25519: vi.fn().mockResolvedValue(true),
  };
});

import { verifyEd25519 } from '../../src/crypto.js';

// Base64-encoded real bundle generated by the Python CLI (from /tmp/test-fixture.json bundleB64 field)
const VALID_BUNDLE_B64 =
  '';

function b64ToArrayBuffer(b64) {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes.buffer;
}

describe('decodeBundle', () => {
  it('decodes a valid bundle without throwing', () => {
    const bundle = decodeBundle(b64ToArrayBuffer(VALID_BUNDLE_B64));
    expect(bundle.fmtVer).toBe(1);
    expect(bundle.threshold).toBe(2);
    expect(bundle.identities.length).toBe(1);
    expect(bundle.signatures.length).toBe(3);
    expect(bundle.identities[0].record.did).toBe('did:local:test-svc');
  });

  it('throws BundleValidationError for unsupported format version', () => {
    // Manually encode a minimal CBOR map with fmt_ver=99 using our canonical encoder
    import('/Users/bensheridan/Documents/GitHub/pki-design/browser/src/cbor-canonical.js').then(({ encodeCbor }) => {
      const raw = encodeCbor({ fmt_ver: 99, val_set: [], identities: [], signatures: [], threshold: 1, expires_at: 9999999999, issued_at: 0, snap_block: 0, snap_root: new Uint8Array(32) });
      expect(() => decodeBundle(raw.buffer)).toThrow(BundleValidationError);
    });
  });
});

describe('validateBundle (via decodeBundle + validateBundle)', () => {
  it('accepts a valid bundle', async () => {
    const bundle = decodeBundle(b64ToArrayBuffer(VALID_BUNDLE_B64));
    // The fixture has a real expiry ~24h from creation time; for this test we extend it
    bundle.expiresAt = Math.floor(Date.now() / 1000) + 86400;
    await expect(validateBundle(bundle)).resolves.toBeTruthy();
  });

  it('throws BundleValidationError for an expired bundle', async () => {
    const bundle = decodeBundle(b64ToArrayBuffer(VALID_BUNDLE_B64));
    bundle.expiresAt = 1; // already expired
    await expect(validateBundle(bundle)).rejects.toThrow(BundleValidationError);
    await expect(validateBundle(bundle)).rejects.toMatchObject({ reason: 'expired' });
  });

  it('throws BundleValidationError (quorum) when too few signatures are valid', async () => {
    const bundle = decodeBundle(b64ToArrayBuffer(VALID_BUNDLE_B64));
    bundle.expiresAt = Math.floor(Date.now() / 1000) + 86400;
    // Make verifyEd25519 return false for all — simulating tampered sigs → 0 valid < threshold 2
    verifyEd25519.mockResolvedValue(false);
    await expect(validateBundle(bundle)).rejects.toThrow(BundleValidationError);
    await expect(validateBundle(bundle)).rejects.toMatchObject({ reason: 'quorum' });
    verifyEd25519.mockResolvedValue(true); // restore
  });
});
